_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    //vUv = (vUv/uTexSize.xy)*2.0-1.0; //Don't redefine like that. Changed from fragCoord to vUv.
    //vUv.x *= uTexSize.x/uTexSize.y;
    vUv = vUv*2 - 1; // Sightly center vUv.

    // Mouse simulation using q variables
    float mouseX = q1*2.0-1.0;
    float mouseY = q2*2.0-1.0;
    float clicked = q3;

    // Audio reactivity
    float sound = (audioLowSmooth + audioHighSmooth + audioMidSmooth)/3.0 * DISTORTION;
    float distortion = 1.0 + sound * 0.15;

    float fractTime = fract(uTime*0.3);
    float tauTime = mod(uTime, TAU);

    float len = length(vUv);
    float angle = atan(vUv.y, vUv.x);

    // Dynamic parameters
    float powLen, sine, arms;

    if (clicked > 0.5) {
        powLen = pow(len, (mouseY*0.5+0.5) * 128.0);
        distortion = pow(distortion, (mouseY*0.5+0.5) * 128.0);
        arms = round((mouseX*0.5+0.5) * 12.0) + 2.0;
    }
else
    {
       distortion = inversesqrt(distortion + 0.001);
       powLen = inversesqrt(len + 0.001);
       arms = 4.0 + sin(uTime*0.3)*2.0;
    }

    // Main pattern
    sine = sin(powLen * (12.0 + audioLow*6.0) * distortion + angle * arms - tauTime * 5.0);
    sine = sqrt(abs(sine)) * (1.0 + audioHigh*0.3);

    // Apply toggle effects
    if (q4 > 0.5) sine = 1.0 - sine;
    if (q5 > 0.5) sine = inversesqrt(sine + 0.001);

    // Final color
    vec3 color = linColor(powLen*distortion*0.7 - fractTime + audioLow*0.1);
    ret = vec4(color * (sine*0.8 + audioMid*0.2 + 0.1), 1.0); //void functions cannot return a value. Use ret instead.

  fragColor = ret;
}

